def insert_faqs_into_file(path: str, faqs: list) -> bool:
    """Insert a faqs={[...]} block immediately before related={category.items}."""
    with open(path, encoding="utf-8") as f:
        content = f.read()

    if 'faqs={[' in content:
        print(f"SKIP (already has faqs): {path}")
        return False

    # Build the FAQ literal
    faq_lines = ["          faqs={["]
    for q, a in faqs:
        # escape backticks just in case
        qe = q.replace('"', '\\"')
        ae = a.replace('"', '\\"')
        faq_lines.append("            {")
        faq_lines.append(f'              q: "{qe}",')
        faq_lines.append(f'              a: "{ae}",')
        faq_lines.append("            },")
    faq_lines.append("          ]}")
    faq_block = "\n".join(faq_lines) + "\n          related={category.items}"

    old_anchor = "          related={category.items}"
    if old_anchor not in content:
        print(f"ERROR (no anchor): {path}")
        return False

    new_content = content.replace(old_anchor, faq_block, 1)
    with open(path, "w", encoding="utf-8") as f:
        f.write(new_content)
    print(f"OK: {path} ({len(faqs)} FAQs)")
    return True


total = 0
applied = 0
for path, faqs in FAQS.items():
    total += 1
    if insert_faqs_into_file(path, faqs):
        applied += 1

print(f"\nApplied to {applied}/{total} pages")
